import { useEffect, useState } from "react";
import { getFantasmas } from "../backend/controllers/fantasmas";
import FantasmaCard from "./FantasmaCard";
import { getEvidencias } from "../backend/controllers/evidencias";

const Body = () => {
  const [fantasmas, setFantasmas] = useState();
  const [inputSort, setInputSort] = useState();
  const [fantasmaFiltro, setFantasmaFiltro] = useState();
  const [evidencias, setEvidencias] = useState([]);

  useEffect(() => {
    getFantasmas().then(
      (data) => (setFantasmas(data), setFantasmaFiltro(data))
    );

    getEvidencias().then((data) => setEvidencias(data));
  }, []);

  const handleFilter = (e) => {
    const inputValue = e.target.value.toLowerCase();
    setInputSort(inputValue);
    setFantasmaFiltro(
      fantasmas.filter((fantasma) =>
        fantasma.nombre.toLowerCase().includes(inputValue)
      )
    );
  };

  return (
    <div>
      {fantasmaFiltro && (
        <>
          <input value={inputSort} onChange={(e) => handleFilter(e)} />
          <div style={{ display: 'flex', flexWrap: 'wrap', margin: '5px', border:'1px solid black'}}>
            {fantasmas?.map((fantasma) => (
              <div style={{ margin: '5px', display: 'flex', alignItems: 'center' }}>
                <input type="checkbox" /> 
              </div>
            ))}
          </div>
          <table>
            <thead>
              <tr>
                <th>Fantasma</th>
                <th>Prueba1</th>
                <th>Prueba2</th>
                <th>Prueba3</th>
                <th>Descripcion</th>
              </tr>
            </thead>
            <tbody>
              {evidencias ? (
                fantasmaFiltro?.map((fantasma) => (
                  <FantasmaCard key={fantasma.id} fantasma={fantasma} />
                ))
              ) : (
                <span>Loading...</span>
              )}
            </tbody>
          </table>
        </>
      )}
    </div>
  );
};

export default Body;
